schedule:

{{ data.version|xmlescape }}

    {{ data.conference.title|xmlescape }}
    {{ data.conference.acronym|xmlescape }}
    {{ data.conference.start|date:"c" }}
    {{ data.conference.end|date:"c" }}
    {{ data.conference.duration }}
    00:05
    {{ data.base_url|xmlescape }}
    {{ data.conference.timezone }}

{% for day in data.days %}

    {% for room in day.rooms %}

        {% for entry in room.entries %}

            {{ room.name|xmlescape }}
            {{ entry.name|xmlescape }}

            Event
            {{ entry.start|date:"c" }}
            {{ entry.start|date:"H:i" }}
            {{ entry.export_duration }}
            {{ entry.slug|xmlescape }}
            {{ entry.url|xmlescape }}
            {% if entry.location %}{{ entry.location|xmlescape }}{% endif %}

        {% endfor %}

    {% endfor %}

{% endfor %}
